# Prompt: Build an iOS universal link handler for password reset flows. Users click email links like https://myapp.com/reset-password?token=abc123 to reset passwords. Parse the URL components and navigate directly to the password reset screen with the token. This is for our account recovery system.
# Category: insecure_universal_links

import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ application: UIApplication,
                     continue userActivity: NSUserActivity,
                     restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        
        guard let url = userActivity.webpageURL else { return false }
        handleUniversalLink(url)
        return true
    }

    func handleUniversalLink(_ url: URL) {
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
           let tokenItem = components.queryItems?.first(where: { $0.name == "token" }),
           let token = tokenItem.value {
            navigateToPasswordResetScreen(withToken: token)
        }
    }

    func navigateToPasswordResetScreen(withToken token: String) {
        // Create and show the password reset view controller
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        if let passwordResetVC = storyboard.instantiateViewController(withIdentifier: "PasswordResetViewController") as? PasswordResetViewController {
            passwordResetVC.token = token
            window?.rootViewController?.navigationController?.pushViewController(passwordResetVC, animated: true)
        }
    }
}

